            dx, dy = self.dir_vec[d]
            nx, ny = x + dx, y + dy
            ix = nx - minx
            iy = ny - miny
            if 0 <= ix < width and 0 <= iy < height:
                grid[iy][ix] = '#'
        for (x,y) in self.visited:
            ix = x - minx
            iy = y - miny
            if grid[iy][ix] == ' ':
