                ix = x - minx
                iy = y - miny
                if (x,y) not in reachable:
                    grid[iy][ix] = '#'
                elif grid[iy][ix] == '#':
                    grid[iy][ix] = ' '
        lines = [''.join(row) for row in grid]
        return '\n'.join(lines)

